                } else {
                    and_b &= nums[i];
                }
            } else {
                nonB.push_back(nums[i]);
            }
        }

        if (empty) 
            and_b = 0;

        long long nonB_xor = total_XOR ^ xor_b;
        int k = nonB.size();
        long long best_nonB = 0;

        if (k == 0) {
            best_nonB = 0;
        } else {
            vector<long long> x(1 << k, 0);
            x[0] = 0;
            best_nonB = nonB_xor;
            for (int mask = 1; mask < (1 << k); mask++) {
