#include <vector>
#include <algorithm>
using namespace std;

long long solve(vector<long long> nums) {
    int n = nums.size();
    if (n == 0) return 0;
    long long total_masks = 1;
    for (int i = 0; i < n; i++) {
        total_masks *= 3;
    }
    vector<long long> powers(n, 1);
    for (int i = 1; i < n; i++) {
        powers[i] = powers[i-1] * 3;
    }
    long long best = 0;
    for (long long mask = 0; mask < total_masks; mask++) {
        long long xorA = 0;
        long long andB = -1;
        long long xorC = 0;
        for (int i = 0; i < n; i++) {
            int g = (mask / powers[i]) % 3;
            if (g == 0) {
